data.content:
For your `ScoreCalculator`, the key MSTest assertions for boundary checking are:

| Scenario | Assertion |
|---|---|
| Grade boundaries (90, 80, 70, 60) | `Assert.AreEqual(expected, actual)` with `[DataRow]` |
| Score in valid range | `Assert.IsInRange(actual, low, high)` |
| Normalized score capped at 100 | `Assert.IsLessThan(upperBound, actual)` or `Assert.AreEqual` |
| Invalid arguments throw | `Assert.ThrowsExactly<ArgumentOutOfRangeException>(...)` |

Here's a complete test class:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc;

    public ScoreCalculatorTests()
    {
        _calc = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_ResultAlwaysInRange()
    {
        var result = _calc.CalculatePercentage(5, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0,  "A", DisplayName = "Boundary: exactly 90 → A")]
    [DataRow(89.9,  "B", DisplayName = "Boundary: just below 90 → B")]
    [DataRow(80.0,  "B", DisplayName = "Boundary: exactly 80 → B")]
    [DataRow(79.9,  "C", DisplayName = "Boundary: just below 80 → C")]
    [DataRow(70.0,  "C", DisplayName = "Boundary: exactly 70 → C")]
    [DataRow(69.9,  "D", DisplayName = "Boundary: just below 70 → D")]
    [DataRow(60.0,  "D", DisplayName = "Boundary: exactly 60 → D")]
    [DataRow(59.9,  "F", DisplayName = "Boundary: just below 60 → F")]
    [DataRow(0.0,   "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(0.0,  100.0, 0.0)]
    [DataRow(100.0, 100.0, 100.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(
        double raw, double maxRaw, double expected)
    {
        Assert.AreEqual(expected, _calc.NormalizeScore(raw, maxRaw));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150.0, 100.0);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50.0, 0.0));
    }
}
```

**Key assertions used:**

- **`Assert.AreEqual`** — exact value checks (percentages, grades)
- **`Assert.IsInRange`** — verify result falls within `[0, 100]`
- **`Assert.ThrowsExactly<T>`** — verify guard clauses throw the exact exception type (not a subclass)
- **`[DataRow]` with `DisplayName`** — parameterized boundary tests at each grade threshold (exactly-at and just-below)
